select v_1 as "c_count", v_2 as "custdist" from (select v_3 as v_1, count(*) as v_2 from (select v_4 as v_5, count(v_6) as v_3 from (select * from (select "c_custkey" as v_4, "c_name" as v_7, "c_address" as v_8, "c_nationkey" as v_9, "c_phone" as v_10, "c_acctbal" as v_11, "c_mktsegment" as v_12, "c_comment" as v_13 from "customer") l left outer join (select * from (select "o_orderkey" as v_6, "o_custkey" as v_14, "o_orderstatus" as v_15, "o_totalprice" as v_16, "o_orderdate" as v_17, "o_orderpriority" as v_18, "o_clerk" as v_19, "o_shippriority" as v_20, "o_comment" as v_21 from "orders") s where  not (v_21 like '%special%requests%')) r on v_4 = v_14) s group by 1) s group by 1) s order by v_2 desc, v_1 desc
